mapper.insert:
/** CmmtPasswdHistDao.insert */
insert into cmmt_passwd_hist (
	 member_id
	,hist_dt
	,enc_passwd
) values (
	 #{memberId}
	,#{histDt}
	,#{encPasswd}
)

mapper.select:
/** CmmtPasswdHistDao.selectList_recent */
select

	,row_number() over (order by hist_dt desc) as rn
from cmmt_passwd_hist
where
	member_id = #{memberId}
offset 0
limit #{cnt}
